import argparse
from kafka.admin import AdminClient, NewTopic, ConfigResource, ConfigResourceType

def create_topic(admin_client, topic_name, num_partitions, replication_factor):
    topic_list = [NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor)]
    admin_client.create_topics(new_topics=topic_list, validate_only=False)

def alter_topic_partitions(admin_client, topic_name, num_partitions):
    topic_partitions = {topic_name: num_partitions}
    admin_client.create_partitions(topic_partitions)

def configure_topic(admin_client, topic_name, configs):
    resources = [ConfigResource(ConfigResourceType.TOPIC, topic_name, configs=configs)]
    admin_client.alter_configs(resources)

def parse_args():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Script')
    parser.add_argument('--bootstrap-server', required=True, help='Kafka bootstrap server')
    parser.add_argument('--create-topic', help='Create a new topic')
    parser.add_argument('--partitions', type=int, help='Number of partitions for the topic')
    parser.add_argument('--replication-factor', type=int, help='Replication factor for the topic')
    parser.add_argument('--alter-partitions', help='Alter partitions for an existing topic')
    parser.add_argument('--alter-config', help='Alter configuration for an existing topic')
    parser.add_argument('--configs', nargs='*', help='Configuration settings in key=value format')
    return parser.parse_args()

def main():
    args = parse_args()
    admin_client = AdminClient({'bootstrap.servers': args.bootstrap_server})
    
    if args.create_topic:
        if args.partitions and args.replication_factor:
            create_topic(admin_client, args.create_topic, args.partitions, args.replication_factor)
        else:
            print("Error: --partitions and --replication-factor are required to create a topic.")
    
    if args.alter_partitions and args.partitions:
        alter_topic_partitions(admin_client, args.alter_partitions, args.partitions)

    if args.alter_config and args.configs:
        configs_dict = dict(config.split('=') for config in args.configs)
        configure_topic(admin_client, args.alter_config, configs_dict)

if __name__ == "__main__":
    main()